    "text_content": "WHERE 1=1 AND is_in_denominador = 1 -- Seção \"Critérios de Exclusão do Denominador (Solicitações válidas)\" AND ts_to_date_gmt BETWEEN init_date AND end_date -- Seção \"Período de Apuração\" AND httpmethod = 'POST' AND is_fvp = 0 AND clientorgid <> serverorgid AND statuscode LIKE '2%' -- Seção \"Critérios de Exclusão do Denominador (Solicitações válidas)\" AND additionalinfo_consentid IS NOT NULL -- Chave de Cruzamento para Dados de Clientes AND endpoint = '/token' AND additionalinfo_granttype = 'AUTHORIZATION_CODE' AND ( is_missing_security = 1 AND endpoint = '/open-banking/resources/v3/resources' – Dados de Clientes ) -- Busca por uso de Negócio Pagamentos Denominador de Pagamentos: -- As colunas que começam com \"is_\" são flags criadas ao longo do processo para validação. WHERE 1=1 AND ts_to_date_gmt BETWEEN init_date AND end_date -- Seção \"Período de Apuração\" AND endpoint = '/open-banking/payments/v4/consents' -- Endpoint específico para Pagamentos AND httpmethod = 'POST' AND statuscode LIKE '2%' -- Seção \"Critérios de Exclusão do Denominador (Solicitações válidas)\" AND ( additionalinfo_dropreason = 'NONE' OR additionalinfo_dropreason IS NULL ) -- Seção \"Critérios de Exclusão do Denominador (Solicitações válidas)\" AND is_paired = 1 -- Seção \"Critérios de Exclusão do Denominador (Solicitações válidas)\" AND is_fvp = 0 AND ( COALESCE(additionalinfo_authorisationflowintent, additionalinfo_authorisationflow) <> 'FIDO_FLOW' OR COALESCE(additionalinfo_authorisationflowintent, additionalinfo_authorisationflow) IS NULL ) AND clientorgid <> serverorgid -- Tratamento de possíveis erros.",
